import{_ as t,o as e,c as i,a2 as l}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Contract Change SOP","description":"","frontmatter":{},"headers":[],"relativePath":"practices/contract-change-sop.md","filePath":"practices/contract-change-sop.md"}'),n={name:"practices/contract-change-sop.md"};function r(s,a,o,c,d,h){return e(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="contract-change-sop" tabindex="-1">Contract Change SOP <a class="header-anchor" href="#contract-change-sop" aria-label="Permalink to &quot;Contract Change SOP&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p>用于修改两个以上项目或仓库共同依赖的 Contract。</p><h2 id="什么时候用" tabindex="-1">什么时候用 <a class="header-anchor" href="#什么时候用" aria-label="Permalink to &quot;什么时候用&quot;">​</a></h2><ul><li>API response shape 变化</li><li>DB schema / RPC / enum 变化</li><li>共享事件、任务状态、通知类型变化</li><li>CLI / MCP 输出契约变化</li><li>删除字段、改名、改语义或改错误码</li></ul><h2 id="角色" tabindex="-1">角色 <a class="header-anchor" href="#角色" aria-label="Permalink to &quot;角色&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>责任</th></tr></thead><tbody><tr><td>Contract Owner</td><td>定义变更和兼容策略</td></tr><tr><td>Producer</td><td>保证输出符合新旧契约</td></tr><tr><td>Consumer</td><td>确认读取兼容和迁移计划</td></tr><tr><td>Reviewer</td><td>检查影响范围、验证和退出条件</td></tr></tbody></table><h2 id="sop" tabindex="-1">SOP <a class="header-anchor" href="#sop" aria-label="Permalink to &quot;SOP&quot;">​</a></h2><ol><li>写清变更类型：兼容 / breaking / 废弃。</li><li>列出所有 Producer 和 Consumer。</li><li>给出迁移顺序和兼容窗口。</li><li>通知受影响 Owner。</li><li>先合并读取兼容，再切换写入。</li><li>跑跨仓验证。</li><li>更新 Contract、Decision、README 和相关项目文档。</li><li>到期删除旧兼容路径。</li></ol><h2 id="breaking-change-额外要求" tabindex="-1">Breaking change 额外要求 <a class="header-anchor" href="#breaking-change-额外要求" aria-label="Permalink to &quot;Breaking change 额外要求&quot;">​</a></h2><p>必须有：</p><ul><li>影响清单</li><li>迁移窗口</li><li>回滚方式</li><li>测试证据</li><li>明确 Owner 批准</li></ul><p>默认发布顺序：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Readers 兼容新旧格式</span></span>
<span class="line"><span>  → Producers 写新格式</span></span>
<span class="line"><span>  → 数据迁移 / 回填</span></span>
<span class="line"><span>  → 删除旧兼容</span></span></code></pre></div><h2 id="通知内容" tabindex="-1">通知内容 <a class="header-anchor" href="#通知内容" aria-label="Permalink to &quot;通知内容&quot;">​</a></h2><p>通知应包含：</p><ul><li>改什么</li><li>为什么改</li><li>影响哪些仓库</li><li>什么时候切换</li><li>谁负责验证</li><li>失败怎么回滚</li></ul><h2 id="完成标准" tabindex="-1">完成标准 <a class="header-anchor" href="#完成标准" aria-label="Permalink to &quot;完成标准&quot;">​</a></h2><ul><li>[ ] 所有消费者已确认</li><li>[ ] 兼容窗口和退出条件明确</li><li>[ ] 跨仓测试或手动验证完成</li><li>[ ] Contract 和索引已更新</li><li>[ ] 旧路径删除时间已记录</li></ul>`,19)])])}const b=t(n,[["render",r]]);export{u as __pageData,b as default};
